// Quora scraper via Apify Quora Scraper actor
const input = $input.first().json;
const keywords = input.keywords || [];
const runId = input.run_id;
const projectId = input.project_id;
const limit = 10;
const results = [];

try {
  const actorResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.apify.com/v2/acts/curious_coder~quora-scraper/runs?waitForFinish=60',
    headers: { 'Authorization': `Bearer ${process.env.APIFY_TOKEN}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      searchQueries: keywords.slice(0, 3),
      maxResults: limit,
    }),
  });

  const datasetId = actorResp?.data?.defaultDatasetId;
  if (datasetId) {
    const items = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.apify.com/v2/datasets/${datasetId}/items?limit=${limit}`,
      headers: { 'Authorization': `Bearer ${process.env.APIFY_TOKEN}` },
    });

    for (const item of (items || []).slice(0, limit)) {
      results.push({
        run_id: runId,
        project_id: projectId,
        source: 'quora',
        raw_text: item.question || item.title || '',
        source_url: item.url || item.link || 'https://quora.com',
        engagement_score: (item.followCount || 0) + ((item.answerCount || 0) * 2),
        upvotes: item.followCount || 0,
        comments: item.answerCount || 0,
        metadata: { topics: item.topics || [] },
      });
    }
  }
} catch (e) {
  return [{ json: { source: 'quora', success: false, error: e.message, count: 0 } }];
}

if (results.length > 0) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${process.env.SUPABASE_URL}/rest/v1/research_results`,
    headers: { 'apikey': process.env.SUPABASE_ANON_KEY, 'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
    body: JSON.stringify(results),
  });
}

return [{ json: { source: 'quora', success: true, count: results.length } }];
